#include<iostream>#include<vector>#include<algorithm>#define ll long longusing namespace std; int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n;        cin>>n;        vector<ll>c(n);        for(int i=0;i<n;i++){            cin>>c[i];        }        sort(c.begin(),c.end());        if(c[0]!=1){            cout<<"no"<<"\n";            continue;        }        ll sum=1;        bool flag=true;        for(int i=1;i<n;i++){            if(c[i]>sum){                cout<<"no"<<"\n";                flag=false;                break;            }            else{                sum+=c[i];            }        }        if(flag){            cout<<"yes"<<"\n";        }    } }